import{_ as i,c as a,o as e,ae as t}from"./chunks/framework.Dh1jimFm.js";const d=JSON.parse('{"title":"CSS核心知识","description":"","frontmatter":{},"headers":[],"relativePath":"document/Css/Css核心.md","filePath":"document/Css/Css核心.md"}'),s={name:"document/Css/Css核心.md"};function n(o,l,r,p,c,h){return e(),a("div",null,l[0]||(l[0]=[t(`<h1 id="css核心知识" tabindex="-1">CSS核心知识 <a class="header-anchor" href="#css核心知识" aria-label="Permalink to &quot;CSS核心知识&quot;">​</a></h1><p>参考 <a href="https://juejin.cn/post/6941206439624966152" target="_blank" rel="noreferrer">https://juejin.cn/post/6941206439624966152</a></p><h2 id="语法" tabindex="-1">语法 <a class="header-anchor" href="#语法" aria-label="Permalink to &quot;语法&quot;">​</a></h2><p>CSS的核心功能是将CSS属性设定为特定的值。一个属性与值的键值对被称为声明，一个声明被{}包裹起来后，组成一个声明块，声明块如果需要作用到具体的HTML元素，则还需要加上选择器。选择器和声明块组成了CSS规则集，简称CSS规则。</p><h2 id="规则" tabindex="-1">@规则 <a class="header-anchor" href="#规则" aria-label="Permalink to &quot;@规则&quot;">​</a></h2><p>CSS规则是样式表的主体，通常样式表会包括大量的规则列表。但有时候也需要再样式表中包括一些其他信息，比如字符集，导入其它外部样式表，字体等，这就是@规则：</p><ul><li>@namespace 告诉css引擎必须考虑XML命名空间</li><li>@media 如果满足媒体查询条件 则条件规则组里的规则生效</li><li>@page 描述打印文档时布局的变化</li><li>@font-face描述将下载的外部字体</li><li>@keyframes 描述css动画的关键帧</li><li>@document 如果文档样式表满足给定条件 则规则组里的规则生效</li><li>@chaeset 用于定义样式表使用的字符集</li><li>@import告诉css引擎引入一个外部样式表 -- link与@import的区别</li><li>@supports用于查询特定的css是否生效 可以结合not、and、or等操作符</li></ul><h2 id="层叠性" tabindex="-1">层叠性 <a class="header-anchor" href="#层叠性" aria-label="Permalink to &quot;层叠性&quot;">​</a></h2><p>CSS是层叠样式表，层叠性是CSS中的核心特性之一，是用于合并来自多个源的属性值的算法。层叠性涉及到CSS选择器的优先级，优先级高样式的覆盖优先级低的样式，同一优先级选择器的样式，后面的声明会覆盖前面的。</p><h2 id="选择器" tabindex="-1">选择器 <a class="header-anchor" href="#选择器" aria-label="Permalink to &quot;选择器&quot;">​</a></h2><p>CSS选择器是CSS的核心之一</p><h3 id="基础选择器" tabindex="-1">基础选择器： <a class="header-anchor" href="#基础选择器" aria-label="Permalink to &quot;基础选择器：&quot;">​</a></h3><ul><li>标签选择器：h1</li><li>类选择器： .checked</li><li>ID选择器： #picker</li><li>通配符选择器： *</li></ul><h3 id="属性选择器" tabindex="-1">属性选择器 <a class="header-anchor" href="#属性选择器" aria-label="Permalink to &quot;属性选择器&quot;">​</a></h3><ul><li>[attr]：指定属性的元素</li><li>[attr=val]：属性等于指定值的元素</li><li>[attr*=val]：属性包含指定值的元素</li><li>[attr^=val]：属性以指定值开头的元素</li><li>[attr$=val]：属性以指定值结尾的元素</li><li>[attr~=val]：属性包含指定值（完整单词）的元素</li><li>[attr|=val]：属性以指定值（完整单词）开头的元素</li></ul><h3 id="组合选择器" tabindex="-1">组合选择器 <a class="header-anchor" href="#组合选择器" aria-label="Permalink to &quot;组合选择器&quot;">​</a></h3><ul><li>相邻兄弟选择器：A + B</li><li>普通兄弟选择器： A ~ B</li><li>子代选择器： A &gt; B</li><li>后代选择器: A B</li></ul><h3 id="伪类" tabindex="-1">伪类 <a class="header-anchor" href="#伪类" aria-label="Permalink to &quot;伪类&quot;">​</a></h3><h4 id="条件伪类" tabindex="-1">条件伪类 <a class="header-anchor" href="#条件伪类" aria-label="Permalink to &quot;条件伪类&quot;">​</a></h4><ul><li>:lang() 基于元素语言来匹配页面元素</li><li>:dir() 匹配特定文字书写方向的元素</li><li>:has() 匹配包含指定元素的元素</li><li>:is() 匹配指定选择器列表里的元素</li><li>:not() 用来匹配不符合一组选择器的元素</li></ul><h4 id="行为伪类" tabindex="-1">行为伪类 <a class="header-anchor" href="#行为伪类" aria-label="Permalink to &quot;行为伪类&quot;">​</a></h4><ul><li>:active 鼠标激活的元素</li><li>:hover 鼠标悬浮的元素</li><li>::selection 鼠标选中的元素</li></ul><h4 id="状态伪类" tabindex="-1">状态伪类 <a class="header-anchor" href="#状态伪类" aria-label="Permalink to &quot;状态伪类&quot;">​</a></h4><ul><li>:target 当前锚点的元素</li><li>:link 未访问的链接元素</li><li>:visited 已访问的链接元素</li><li>:focus 输入聚焦的表单元素 ....</li></ul><h4 id="结构伪类" tabindex="-1">结构伪类 <a class="header-anchor" href="#结构伪类" aria-label="Permalink to &quot;结构伪类&quot;">​</a></h4><ul><li>:empty 无子元素的元素</li><li>:nth-child(n) 元素中指定顺序索引的元素</li><li>:nth-last-child(n) 元素中指定逆序索引的元素</li><li>:first-child 元素中第一个的元素</li><li>:last-child 元素中最后一个的元素</li><li>:nth-of-type(n) 元素中指定顺序索引的标签 ...</li></ul><h4 id="伪元素" tabindex="-1">伪元素 <a class="header-anchor" href="#伪元素" aria-label="Permalink to &quot;伪元素&quot;">​</a></h4><ul><li>::before 在元素前插入内容</li><li>::after 在元素后插入内容</li></ul><h2 id="优先级" tabindex="-1">优先级 <a class="header-anchor" href="#优先级" aria-label="Permalink to &quot;优先级&quot;">​</a></h2><p>行内样式 &gt; ID选择器 &gt; 类选择器 &gt; 标签选择器</p><ul><li>10000：!important</li><li>01000：内敛样式</li><li>00100：ID选择器</li><li>00010：类选择器、伪类选择器、属性选择器</li><li>00001：元素选择器、伪元素选择器</li><li>00000：通配符选择器、后代选择器、兄弟选择器</li></ul><p>使用important的注意事项：</p><ul><li>一定要优先考虑使用样式规则的优先级来解决问题 而不是!important</li><li>只有在需要覆盖全站或外部CSS的特定页面中使用!important</li><li>永远不要在插件中使用!important</li><li>永远不要在全站范围的CSS代码中使用!important</li></ul><h2 id="继承性" tabindex="-1">继承性 <a class="header-anchor" href="#继承性" aria-label="Permalink to &quot;继承性&quot;">​</a></h2><p>在CSS中有一个很重要的特性就是子元素会继承父元素对应属性计算后的值。如果CSS中不存在继承性，name我们可能需要为不同文本的标签都设置一下color等属性，会导致CSS文件大小无限增大。</p><p>存在继承的属性：</p><ul><li>字体相关：font-family、font-style、font-size、font-weight等</li><li>文本相关：text-align、text-indent、text-decoration、text-shadow、letter-spacing、word-spacing、white-space、line-height、color等</li><li>列表相关：list-style等</li><li>其它属性：visibility、cursor等</li></ul><p>对于其它默认不继承的属性也可以通过一下几个属性值来控制继承行为：</p><ul><li>inherit 继承父元素对应属性的计算值</li><li>initial 应用该属性的默认值</li><li>unset 如果属性是默认可继承的 则继承，都则去默认值</li><li>revert 同unset 兼容性差</li></ul><h2 id="文档流" tabindex="-1">文档流 <a class="header-anchor" href="#文档流" aria-label="Permalink to &quot;文档流&quot;">​</a></h2><p>CSS中 会把内容从左到右，从上到下按顺序进行排列显示。正常情况页面会被分割成一行一行显示，每行可能由多列组成，所以视觉上是从上到下从左到右，这就是CSS中的流式布局，又叫文档流。</p><p>文档流的几个特性：</p><ul><li>块级元素默认占满整行，所以多个块级盒子是从上到下排列的</li><li>内联元素默认会在一行里一列一列的排布，当一行放不下时，自动切换到下一行</li></ul><p>脱离文档流指正常节点脱离文档流后，在正常文档流中的其它节点将忽略该节点并填补其原来的空间。文档一旦脱离文档流，计算其父节点高度时不会将其高度纳入，脱流节点不占据空间。 如何脱离文档流：</p><ul><li>浮动</li><li>定位：绝对定位、固定定位及满足条件的粘性定位</li></ul><h2 id="盒模型" tabindex="-1">盒模型 <a class="header-anchor" href="#盒模型" aria-label="Permalink to &quot;盒模型&quot;">​</a></h2><p>在CSS中任何元素都可以看成是一个盒子，而一个盒子是由4部分组成：内容、内边距、边框、外边距。 盒模型有两种：标准盒模型和IE盒模型，分别由W3C和IE制定的标准。 标准盒模型认为：盒子的实际尺寸 = 内容(设置的宽高) + 内边距 + 边框，设置内边距和边框会撑大盒子实际尺寸； IE盒模型认为：盒子的实际尺寸 = 设置的宽高 = 内容 + 内边距 + 边框，设置内边距和边框不会撑大盒子实际尺寸，而是会挤压盒子的内容区域； 在CSS3中新增了一个box-sizing属性，允许设置盒模型标准：</p><ul><li>content-box 标准盒模型</li><li>border-box IE盒模型</li><li>padding-box 只有padding计入width，border不计入；兼容性很差，只有低版本firefox支持</li></ul><h2 id="视觉格式化模型" tabindex="-1">视觉格式化模型 <a class="header-anchor" href="#视觉格式化模型" aria-label="Permalink to &quot;视觉格式化模型&quot;">​</a></h2><p>规定页面中多个盒子的排列规则，盒子该怎么摆放、渲染成什么样子，盒模型也包含在这个规则里。视觉格式化模型，大体将页面中盒子的排列分为三种方式： 常规流、浮动、定位。</p><h2 id="格式化上下文" tabindex="-1">格式化上下文 <a class="header-anchor" href="#格式化上下文" aria-label="Permalink to &quot;格式化上下文&quot;">​</a></h2><p>格式化上下文是CSS2.1规范中的一个概念，大概是说页面中的一块渲染区域，规定了渲染区域内部的子元素是如何排版以及相互作用的。</p><p>不同类型的盒子有不同的何世华上下文，大概有这4类：</p><ul><li>BFC 块级格式化上下文</li><li>IFC 行内格式化上下文</li><li>FFC 弹性格式化上下文</li><li>GFC 栅格格式化上下文</li></ul><p>其中BFC和IFC在CSS中极其重要，直接影响了网页布局</p><h3 id="bfc" tabindex="-1">BFC <a class="header-anchor" href="#bfc" aria-label="Permalink to &quot;BFC&quot;">​</a></h3><p>块级格式化上下文，它是一个独立的渲染区域，只有块级盒子参与，规定了内部的块级盒子如何布局，并且与这个区域外部毫不相干</p><p>BFC渲染规则：</p><ul><li>内部的盒子会在垂直方向，一个接一个地放置</li><li>盒子垂直方向的距离由margin决定，属于同一个BFC的两个相邻盒子的margin会发生重叠</li><li>每个元素的margin的左边，与包含块border的左边相接触(对于从左往右的格式化，否则相反)，即使存在浮动也是如此</li><li>BFC区域不会与float盒子重叠</li><li>BFC就是页面上的一个隔离的独立容器，容器里面的子元素不会有影响到外面的元素，外面的元素也不会影响到里面的元素</li><li>计算BFC高度时，浮动元素也参与计算</li></ul><p>如何创建BFC</p><ul><li>根元素 html</li><li>非溢出的可见元素 overflow不为visible</li><li>设置浮动 float属性不为none</li><li>设置定位 position为absolute或fixed</li><li>定义成块级的非块级元素：display:inline-block、table-cell、table-caption、flex、inline-flex、inline-grid</li></ul><p>BFC的应用场景： 自适应两栏布局 内部清除浮动 防止垂直margin合并 -- 同属于一个BFC才会发生margin合并，给两个盒子外层分别套一个盒子并触发其BFC，就不会产生margin合并了</p><h3 id="ifc" tabindex="-1">IFC <a class="header-anchor" href="#ifc" aria-label="Permalink to &quot;IFC&quot;">​</a></h3><p>IFC的形成条件很简单，块级元素中仅包含内联级别元素，当IFC中有块级元素插入时，会产生两个匿名块将父元素分割开来，产生两个IFC</p><p>IFC渲染规则：</p><ul><li>子元素在水平方向上一个接一个排列，在垂直方向上将以容器顶部开始向下排列</li><li>节点无法声明宽高，margin和padding在水平方向有效在垂直方向无效</li><li>节点在垂直方向以不同形式对齐</li><li>能把在一行上的框都完全包含进去一个矩形区域，被称为改行的线盒。线盒的宽度是由包含块和与其中的浮动来决定</li><li>IFC中 line box 一般左右边贴紧其包含块，但float元素会优先排列</li><li>IFC中的line box 高度由line-height计算规则来确定，同个IFC下多个line box 高度可能会不同</li><li>当内联级盒子的总宽度少于包含它们的line box时，其水平渲染规则由text-align属性值来决定</li><li>当一个内联盒子超过父元素宽度时，它会被分割成多个盒子，如果子元素未设置强制换行，将溢出父元素</li></ul><p>IFC的应用场景：</p><ul><li>水平居中 text-align:center</li><li>垂直居中 vertical-align:middle</li></ul><h2 id="层叠上下文" tabindex="-1">层叠上下文 <a class="header-anchor" href="#层叠上下文" aria-label="Permalink to &quot;层叠上下文&quot;">​</a></h2><p>在电脑屏幕上的页面其实是一个三维空间，水平方向是X轴，竖直方向是Y轴，而屏幕到眼睛方向可以看成是Z轴。众多HTML元素依据自己定义的属性的优先级在Z轴上按照一定的顺序排开，而这其实就是层叠上下文所要描述的东西。</p><p>如何产生一个层叠上下文：</p><ul><li>html文档根元素</li><li>声明position为absolute/relative且z-index不为auto的元素</li><li>声明position为fixed/sticky的元素</li><li>flex容器的子元素，且z-index值不为auto</li><li>grid容器的子元素，且z-index不为auto</li><li>opacity属性值小于1的元素</li><li>mix-blend-mode属性值不为normal的元素</li><li>以下属性值不为none的元素： <ul><li>transform</li><li>filter</li><li>perspective</li><li>clip-path</li><li>mask/mask-image/mask-border</li></ul></li><li>isolation 属性值为 isolate 的元素</li><li>-webkit-overflow-scrolling 属性值为 touch 的元素</li><li>will-change 值设定了任一属性而该属性在 non-initial 值时会创建层叠上下文的元素</li><li>contain 属性值为 layout、paint 或包含它们其中之一的合成值（比如 contain: strict、contain: content）的元素</li></ul><p>层叠等级：层叠等级指节点在三维空间Z轴的上下顺序，分两种情况：</p><ul><li>在统一个层叠上下文中，它描述定义的是该层叠上下文中的层叠上下文元素在Z轴上的上下顺序</li><li>在其它普通元素中，它描述的是这些普通元素在Z轴上的上下顺序</li></ul><p>层叠顺序（从下往上）：</p><ul><li>层叠上下文的border和background</li><li>z-index&lt;0的子节点</li><li>标准流内块级非定位的子节点</li><li>浮动非定位的子节点</li><li>标准流内行内非定位的子节点</li><li>z-index为auto/0的子节点</li><li>z-index &gt; 0的子节点</li></ul><p>如何比较两个元素的层叠等级：</p><ul><li>1.在统一层叠上下文中，按照上面顺序比较</li><li>2.不再同意层叠上下文中时，需要比较两个元素分别所处的层叠上下文的等级</li><li>3.如果两个元素在同一层叠上下文，且层叠顺序相同，则在HTML中定义顺序越后面的层叠等级越高</li></ul><h2 id="值和单位" tabindex="-1">值和单位 <a class="header-anchor" href="#值和单位" aria-label="Permalink to &quot;值和单位&quot;">​</a></h2><p>CSS的声明由属性和值组成，而值的类型有许多种：</p><ul><li>数值 长度值，如width等</li><li>百分比 可以用于指定尺寸或长度等</li><li>颜色 可以指定字体颜色或背景颜色等</li><li>坐标位置 以屏幕左上角为原点的位置，如top、bottom、left、right等</li><li>函数 用于指定资源路径或背景色的渐变 如 url()、linear-gradient()</li></ul><p>CSS的单位： px 设备像素(Device pixels) 设备像素币(DPR) 像素密度(DPI/PPI) 设备独立像素(DIP) em rem vw/vh</p><h2 id="颜色体系" tabindex="-1">颜色体系 <a class="header-anchor" href="#颜色体系" aria-label="Permalink to &quot;颜色体系&quot;">​</a></h2><p>CSS中颜色值的类型 大概可以分为下面几类：</p><ul><li>颜色关键字 red等</li><li>transparent关键字 透明色</li><li>currentColor关键字 会取当前元素继承父级元素的文本颜色值或声明的文本颜色值</li><li>RGB颜色 rgb、rgba、十六进制</li><li>HSL颜色</li></ul><h2 id="媒体查询" tabindex="-1">媒体查询 <a class="header-anchor" href="#媒体查询" aria-label="Permalink to &quot;媒体查询&quot;">​</a></h2><p>媒体查询是指针对不同的设备、特定的设备特征或者参数进行定制化的修改网站样式</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;link rel=&quot;stylesheet&quot; src=&quot;styles.css&quot; media=&quot;screen&quot; /&gt;</span></span>
<span class="line"><span>&lt;link rel=&quot;stylesheet&quot; src=&quot;styles.css&quot; media=&quot;print&quot; /&gt;</span></span></code></pre></div><p>以上media值支持的类型：</p><ul><li>all 适用于所有设备</li><li>适用于在打印预览模式下载屏幕上查看的分页材料和文档</li><li>screen 主要用于屏幕</li><li>speech 主要用于语音合成器</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/* 用户设备的最小高度为680px或为纵向模式的屏幕设备 */</span></span>
<span class="line"><span>@media (min-height: 680px), screen and (orientation: portrait) {}</span></span></code></pre></div><p>@media支持的逻辑操作符</p><ul><li>and 查询条件都满足才生效</li><li>not 查询条件取反</li><li>only 整个查询匹配的时候才生效 常用于兼容低版本浏览器</li><li>逗号或or 查询条件满足一项即可匹配</li></ul><h2 id="css样式" tabindex="-1">CSS样式 <a class="header-anchor" href="#css样式" aria-label="Permalink to &quot;CSS样式&quot;">​</a></h2><h3 id="css引入方式" tabindex="-1">CSS引入方式 <a class="header-anchor" href="#css引入方式" aria-label="Permalink to &quot;CSS引入方式&quot;">​</a></h3><ul><li>内联样式：直接将样式写在标签上，只对当前标签有效</li><li>嵌入样式：在head标签内的style标签中写入样式，对当前页面有效</li><li>链接样式/外联样式：使用link标签引入css</li><li>导入样式：在style中使用@import导入样式，或者在css文件中使用@import导入其它样式</li></ul><h3 id="link导入css与-import导入css的区别" tabindex="-1">link导入css与@import导入css的区别 <a class="header-anchor" href="#link导入css与-import导入css的区别" aria-label="Permalink to &quot;link导入css与@import导入css的区别&quot;">​</a></h3><ul><li>link是XHTML标签，它不仅可以引入css文件，还可以引入网站图标、图片等文件(type属性设置类型)或设置媒体查询</li><li>@import是CSS提供的语法规则，只能用来加载css</li><li>link引入css文件，页面载入的同时加载css文件; @import则会在页面完全载入之后加载css文件，在网络较慢的情况下，一开始会没有css样式</li><li>link在浏览器中没有兼容问题；@import是css2.1中提出的，低版本浏览器不会支持</li><li>link中的css可以被js获取进而控制DOM，而@import不支持</li></ul><h3 id="css选择器权重" tabindex="-1">CSS选择器权重 <a class="header-anchor" href="#css选择器权重" aria-label="Permalink to &quot;CSS选择器权重&quot;">​</a></h3><ul><li>针对同一元素标签 当设置了不同选择器时 需要判断权重值大小 权重值越大优先级越高</li><li>权重排序： !important &gt; 行内样式 &gt; id &gt; 类|伪类|属性 &gt; 标签 &gt; 通配符 &gt; 继承</li><li>CSS层叠性：针对同一标签元素 当设置了不同的选择器时 权重高的层叠掉权重低的样式</li></ul><h2 id="css的overflow属性" tabindex="-1">CSS的overflow属性 <a class="header-anchor" href="#css的overflow属性" aria-label="Permalink to &quot;CSS的overflow属性&quot;">​</a></h2><ul><li>overflow是CSS的简写属性 它设置了元素溢出时所需的行为 即当元素的内容太大而无法适应它的块级格式化上下文时的行为</li><li>这个属性是以下属性的简写： <ul><li>overflow-x</li><li>overflow-y</li><li>所以overflow可以设置一个或两个属性 设置两个属性时 分别设置这两个属性 设置一个属性时 这两个属性都会使用这个一个值</li></ul></li><li>overflow的属性值有以下5个： <ul><li>visible: 溢出的内容不能被裁剪并且可能渲染到盒子外部</li><li>hidden: 溢出的内容会被裁剪以适应盒子 不提供滚动条 也不支持用户滚动(比如拖拽或滚轮) 但是内容可以以编程方式(js)滚动 所以仍是一个滚动容器;同时会启动新的块级格式化上下文 所以可用于清除浮动</li><li>clip: 类似hidden 溢出内容会以被裁剪 区别在于clip禁止所有滚动 包括编程方式(js)滚动 盒子不是一个滚动容器; 不会启动新的块级格式化上下文</li><li>scroll: 溢出内容被裁剪 但是浏览器始终会显示滚动条 并可以通过滚动查看溢出内容</li><li>auto: 取决于内容是否溢出 如果内容没有溢出 看起来跟visible一样 但是仍然会创建新的块级格式化上下文;如果内容溢出 则浏览器会提供滚动条 效果跟scroll类似</li><li>overlay: 行为与auto相同 但是滚动条绘制在内容之上 而不是占据空间</li></ul></li><li>JS的Element.scrollTop属性可用于滚动HTML元素 即使overflow设置为hidden</li></ul><h2 id="css中使用var变量" tabindex="-1">css中使用var变量 <a class="header-anchor" href="#css中使用var变量" aria-label="Permalink to &quot;css中使用var变量&quot;">​</a></h2><ul><li>var(--name, value) name必填，value可选，name必须以 -- 开头</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;!DOCTYPE html&gt;</span></span>
<span class="line"><span>&lt;html lang=&quot;en&quot;&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;head&gt;</span></span>
<span class="line"><span>    &lt;meta charset=&quot;UTF-8&quot;&gt;</span></span>
<span class="line"><span>    &lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0&quot;&gt;</span></span>
<span class="line"><span>    &lt;title&gt;Document&lt;/title&gt;</span></span>
<span class="line"><span>    &lt;link rel=&quot;shortcut icon&quot; href=&quot;http://hanhuankang.com/favicon.ico&quot; /&gt;</span></span>
<span class="line"><span>    &lt;style&gt;</span></span>
<span class="line"><span>        #box {</span></span>
<span class="line"><span>            color: var(--box-color);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    &lt;/style&gt;</span></span>
<span class="line"><span>&lt;/head&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;body&gt;</span></span>
<span class="line"><span>    &lt;div id=&quot;box&quot;&gt;颜色改变&lt;/div&gt;</span></span>
<span class="line"><span>&lt;/body&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;/html&gt;</span></span>
<span class="line"><span>&lt;script&gt;</span></span>
<span class="line"><span>// var(--name, value)</span></span>
<span class="line"><span>var box = document.getElementById(&quot;box&quot;);</span></span>
<span class="line"><span>box.style.setProperty(&quot;--box-color&quot;, &quot;red&quot;);</span></span>
<span class="line"><span>setTimeout(() =&gt; {</span></span>
<span class="line"><span>    box.style.setProperty(&quot;--box-color&quot;, &quot;skyblue&quot;);</span></span>
<span class="line"><span>}, 2000);</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre></div>`,105)]))}const b=i(s,[["render",n]]);export{d as __pageData,b as default};
